CREATE TABLE customers(customer_id INT PRIMARY KEY,customer_name VARCHAR(100),gender VARCHAR(10),phone VARCHAR(15),email VARCHAR(100),city VARCHAR(50),state VARCHAR(50),created_date DATE);
CREATE TABLE accounts(account_id VARCHAR(10) PRIMARY KEY,customer_id INT,account_type VARCHAR(20),opening_balance DECIMAL(12,2),current_balance DECIMAL(12,2),branch VARCHAR(50),open_date DATE);
CREATE TABLE bank_transactions(transaction_id INT PRIMARY KEY,account_id VARCHAR(10),transaction_date DATETIME,transaction_type VARCHAR(20),amount DECIMAL(12,2),balance_after_transaction DECIMAL(12,2),remarks VARCHAR(100));
